   519→void GrpcMuxImpl::onStreamEstablished() {
   520→  first_stream_request_ = true;
   521→  grpc_stream_->maybeUpdateQueueSizeStat(0);
   522→  clearNonce();
   523→  request_queue_ = std::make_unique<std::queue<std::string>>();
   524→  for (const auto& type_url : subscriptions_) {
   525→    queueDiscoveryRequest(type_url);
