    14→namespace Envoy {
    15→namespace Upstream {
    16→
    17→std::vector<std::string>
    18→CdsApiHelper::onConfigUpdate(const std::vector<Config::DecodedResourceRef>& added_resources,
    19→                             const Protobuf::RepeatedPtrField<std::string>& removed_resources,
    20→                             const std::string& system_version_info) {
    21→  Config::ScopedResume maybe_resume_eds_leds_sds;
    22→  if (cm_.adsMux()) {
    23→    // A cluster update pauses sending EDS and LEDS requests.
    24→    const std::vector<std::string> paused_xds_types{
    25→        Config::getTypeUrl<envoy::config::endpoint::v3::ClusterLoadAssignment>(),
    26→        Config::getTypeUrl<envoy::config::endpoint::v3::LbEndpoint>(),
    27→        Config::getTypeUrl<envoy::extensions::transport_sockets::tls::v3::Secret>()};
    28→    maybe_resume_eds_leds_sds = cm_.adsMux()->pause(paused_xds_types);
    29→  }
    30→
    31→  ENVOY_LOG(info, "{}: add {} cluster(s), remove {} cluster(s)", name_, added_resources.size(),
    32→            removed_resources.size());
    33→
    34→  std::vector<std::string> exception_msgs;
    35→  absl::flat_hash_set<std::string> cluster_names(added_resources.size());
    36→  bool any_applied = false;
    37→  uint32_t added_or_updated = 0;
    38→  uint32_t skipped = 0;
    39→  for (const auto& resource : added_resources) {
    40→    envoy::config::cluster::v3::Cluster cluster;
    41→    TRY_ASSERT_MAIN_THREAD {
    42→      cluster = dynamic_cast<const envoy::config::cluster::v3::Cluster&>(resource.get().resource());
    43→      if (!cluster_names.insert(cluster.name()).second) {
    44→        // NOTE: at this point, the first of these duplicates has already been successfully applied.
    45→        exception_msgs.push_back(
    46→            fmt::format("{}: duplicate cluster {} found", cluster.name(), cluster.name()));
    47→        continue;
    48→      }
    49→      if (cm_.addOrUpdateCluster(cluster, resource.get().version())) {
    50→        any_applied = true;
    51→        ENVOY_LOG(debug, "{}: add/update cluster '{}'", name_, cluster.name());
    52→        ++added_or_updated;
    53→      } else {
    54→        ENVOY_LOG(debug, "{}: add/update cluster '{}' skipped", name_, cluster.name());
    55→        ++skipped;
    56→      }
    57→    }
    58→    END_TRY
    59→    CATCH(const EnvoyException& e,
    60→          { exception_msgs.push_back(fmt::format("{}: {}", cluster.name(), e.what())); });
    61→  }
    62→
    63→  for (const auto& resource_name : removed_resources) {
    64→    if (cm_.removeCluster(resource_name)) {
    65→      any_applied = true;
    66→      ENVOY_LOG(debug, "{}: remove cluster '{}'", name_, resource_name);
    67→    }
    68→  }
    69→
    70→  ENVOY_LOG(info, "{}: added/updated {} cluster(s), skipped {} unmodified cluster(s)", name_,
    71→            added_or_updated, skipped);
    72→
    73→  if (any_applied) {
    74→    system_version_info_ = system_version_info;
    75→  }
    76→  return exception_msgs;
    77→}
    78→
    79→} // namespace Upstream
    80→} // namespace Envoy
